""use client";

import { useState, useEffect } from "react";
import { useRouter } from "next/navigation";

export interface UserSession {
  name: string;
  email: string;
  role: string;
  tenantId: string;
  initials: string;
}

export function useAuth() {
  const [user, setUser] = useState<UserSession | null>(null);
  const [loading, setLoading] = useState(true);
  const router = useRouter();

  useEffect(() => {
    const savedUserJson = localStorage.getItem("vg-user");
    if (savedUserJson) {
      try {
        setUser(JSON.parse(savedUserJson));
      } catch (e) {
        console.error("Gagal mem-parsing sesi user di hook", e);
      }
    }
    setLoading(false);
  }, []);

  const login = (sessionData: UserSession) => {
    localStorage.setItem("vg-user", JSON.stringify(sessionData));
    setUser(sessionData);
    router.push("/dashboard");
  };

  const logout = () => {
    localStorage.removeItem("vg-user");
    setUser(null);
    router.push("/login");
  };

  return {
    user,
    loading,
    isAuthenticated: !!user,
    login,
    logout,
  };
}
"

